class Solution {
public:
    int maximumLengthSubstring(string s) {
        int left = 0;
        int max_len = 0;
        vector<int> count(26, 0);
        for (int right = 0; right < s.size(); ++right) {
            ++count[s[right] - 'a'];
            while (true) {
                bool invalid = false;
                for (int i = 0; i < 26; ++i) {
                    if (count[i] > 2) {
                        invalid = true;
                        break;
                    }
                }
                if (!invalid) break;
                --count[s[left] - 'a'];
                ++left;
            }
            max_len = max(max_len, right - left + 1);
        }
        return max_len;
    }
};

